131	      TensorStride stride_xformed_act,                                     // [n,z,p,q,k]
132	      ShapePadding lower_padding,                                          // [pad_d, pad_h, pad_w]
133	      ShapePadding upper_padding,                                          // [pad_d, pad_h, pad_w]
134	      TraversalStride tstride,                                             // [stride_d, stride_h, stride_w]
